import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { NavbarComponent } from './components/navbar/navbar.component';
import { DashboardComponent } from './features/dashboard/dashboard.component'; 
import { SidebarComponent } from './components/components/sidebar/sidebar.component'; 
import { AppointmentComponent } from './features/appointment/appointment.component'; 
import { StaffComponent } from './features/staff/staff.component'; 
import { LabComponent } from './features/lab/lab.component'; 
import { PatientComponent } from './features/patient/patient.component';
import { DoctorComponent } from './features/doctor/doctor.component'; 
import { LoginComponent } from './login/login.component';
import { DashboardLayoutComponent } from './dashboard-layout/dashboard-layout.component';
import { InvoiceComponent } from './features/invoice/invoice.component';
import { PharmacyComponent } from './features/pharmacy/pharmacy.component';
import { AuthGuard } from './guards/auth.guard';
const routes: Routes = [
  { path: '', redirectTo: 'login', pathMatch: 'full' },
    { path: 'login', component: LoginComponent},

  {
    path: '',
    component: DashboardLayoutComponent,
      canActivate: [AuthGuard],

    children: [
  { path: 'dashboard', component:DashboardComponent },
  { path: 'staff', component:StaffComponent },
  { path: 'lab', component:LabComponent },
  { path: 'patient', component:PatientComponent },
  { path: 'doctor', component: DoctorComponent},
  { path: 'navbar', component:NavbarComponent },
  { path: 'invoice', component:InvoiceComponent },
  { path: 'pharmacy', component:PharmacyComponent },

 { path: 'sidebar', component:SidebarComponent },
 { path: 'appointment', component:AppointmentComponent },
    ]
  },
  { path: '**', redirectTo: 'login' }
]; 

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
